from collections import defaultdict
class Solution(object):
    def countCompleteSubarrays(self, nums):
        total = len(set(nums))
        n = len(nums)
        ans = 0
        cnt = defaultdict(int)
        lo = 0
        distinct = 0
        for hi in range(n):
            if cnt[nums[hi]] == 0:
                distinct += 1
            cnt[nums[hi]] += 1
            while distinct == total:
                ans += n - hi
                cnt[nums[lo]] -= 1
                if cnt[nums[lo]] == 0:
                    distinct -= 1
                lo += 1
        return ans
